import datetimefrom libs.database.model import Modelfrom libs.database.types import Date, Date, Number, Char, Clobclass ProcessItems(Model):    __tablename__ = 'process_items'    id = Number(field="id")    date_created = Date(field="date_created", default=datetime.datetime.now())    date_modified = Date(field="date_modified")    process_id = Number(field="process_id")    account_id = Number(field="account_id")    user_id = Number(field="user_id")    tool_id = Number(field="tool_id")    item_external_id = Number(field="item_external_id")    http_status = Number(field="http_status")    status = Number(field="status")    is_refunded = Char(field="is_refunded")    http_body = Clob(field="http_body")